    public SamlAuthenticationResponse processSamlResponse(String samlResponse, HttpServletRequest request) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        DocumentBuilder builder = factory.newDocumentBuilder();
        ByteArrayInputStream inputStream = new ByteArrayInputStream(samlResponse.getBytes());
        Document document = builder.parse(inputStream);

        Element responseElement = document.getDocumentElement();
        Response response = (Response) org.opensaml.xmlsec.signature.support.SignatureValidator.unmarshall(responseElement);

        if (!validateResponse(response)) {
            throw new SecurityException("Invalid SAML response");
        }

        Assertion assertion = getAssertionFromResponse(response);
        if (assertion == null) {
            throw new SecurityException("No assertion found in SAML response");
        }

        if (!validateAssertion(assertion)) {
            throw new SecurityException("Invalid SAML assertion");
        }

        Map<String, Object> userAttributes = extractUserAttributes(assertion);
        String userId = (String) userAttributes.get("userId");
        String email = (String) userAttributes.get("email");

        HttpSession session = request.getSession();
        session.setAttribute("userId", userId);
        session.setAttribute("email", email);
        session.setAttribute("authenticated", true);
        session.setAttribute("userAttributes", userAttributes);

        return new SamlAuthenticationResponse(userId, email, userAttributes);
    }

    private boolean validateResponse(Response response) {
        if (response == null) return false;
        if (response.getVersion() != SAMLVersion.VERSION_20) return false;
        if (response.getStatus() == null) return false;
        return response.getStatus().getStatusCode().getValue().equals(SAMLConstants.STATUS_SUCCESS);
    }

    private Assertion getAssertionFromResponse(Response response) {
        if (response.getAssertions() == null || response.getAssertions().isEmpty()) {
            return null;
        }
        return response.getAssertions().get(0);
    }

    private boolean validateAssertion(Assertion assertion) {
        if (assertion == null) return false;
        if (assertion.getSubject() == null) return false;
        if (assertion.getConditions() == null) return false;
        return true;
    }

    private Map<String, Object> extractUserAttributes(Assertion assertion) {
        Map<String, Object> attributes = new HashMap<>();

        Subject subject = assertion.getSubject();
        if (subject != null && subject.getNameID() != null) {
            attributes.put("userId", subject.getNameID().getValue());
        }

        if (assertion.getAttributeStatements() != null) {
            for (AttributeStatement attrStatement : assertion.getAttributeStatements()) {
                for (Attribute attribute : attrStatement.getAttributes()) {
                    String attrName = attribute.getName();
                    if (attribute.getAttributeValues() != null && !attribute.getAttributeValues().isEmpty()) {
                        Object value = attribute.getAttributeValues().get(0).getValue();
                        attributes.put(attrName, value);
                    }
                }
            }
        }

        if (assertion.getAuthnStatements() != null && !assertion.getAuthnStatements().isEmpty()) {
            AuthnStatement authnStatement = assertion.getAuthnStatements().get(0);
            if (authnStatement.getAuthnContext() != null && 
                authnStatement.getAuthnContext().getAuthnContextClassRef() != null) {
                attributes.put("authnContext", 
                    authnStatement.getAuthnContext().getAuthnContextClassRef().getURI());
            }
        }

        return attributes;
    }
