@Configuration
@Component
public class SamlSessionManager {
    private final Map<String, Map<String, Object>> activeSessions = new HashMap<>();

    public void createSession(String sessionId, Map<String, Object> attributes) {
        activeSessions.put(sessionId, attributes);
    }

    public Map<String, Object> getSessionAttributes(String sessionId) {
        return activeSessions.get(sessionId);
    }

    public void invalidateSession(String sessionId) {
        activeSessions.remove(sessionId);
    }

    public boolean isSessionValid(String sessionId) {
        return activeSessions.containsKey(sessionId);
    }
}

@RestController
@RequestMapping("/saml")
public class SamlController {

    @Autowired
    private SamlAuthenticationService authenticationService;

    @PostMapping("/acs")
    public ResponseEntity<?> processAssertion(@RequestBody String samlResponse,
                                             HttpServletRequest request,
                                             HttpServletResponse response) {
        try {
            SamlAuthenticationResponse authResponse = authenticationService.processSamlResponse(samlResponse, request);
            return ResponseEntity.ok(authResponse);
        } catch (Exception e) {
            return ResponseEntity.status(401).body("Authentication failed: " + e.getMessage());
        }
    }

    @GetMapping("/logout")
    public ResponseEntity<?> logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }
        return ResponseEntity.ok("Logged out successfully");
    }

    @GetMapping("/status")
    public ResponseEntity<?> getStatus(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null || session.getAttribute("authenticated") == null) {
            return ResponseEntity.status(401).body("Not authenticated");
        }
        return ResponseEntity.ok("Authenticated");
    }
}

